-- =============================================-- VAULT STORE — Supabase Schema-- Run this in Supabase SQL Editor-- =============================================
-- Enable UUID extensioncreate extension if not exists "uuid-ossp";
-- ─────────────────────────────────────────────-- PROFILES (extends Supabase auth.users)-- ─────────────────────────────────────────────create table public.profiles (  id uuid references auth.users on delete cascade primary key,  name text,  email text,  avatar_url text,  is_admin boolean default false,  vault_balance numeric(10,2) default 0,  created_at timestamptz default now());
-- Auto-create profile on signupcreate or replace function public.handle_new_user()returns trigger as $$begin  insert into public.profiles (id, email, name)  values (new.id, new.email, new.raw_user_meta_data->>'name');  return new;end;$$ language plpgsql security definer;
create trigger on_auth_user_created  after insert on auth.users  for each row execute procedure public.handle_new_user();
-- ─────────────────────────────────────────────-- CATEGORIES-- ─────────────────────────────────────────────create table public.categories (  id serial primary key,  name text not null unique,  slug text not null unique,  icon text,  created_at timestamptz default now());
insert into public.categories (name, slug, icon) values  ('Automation', 'automation', ' '),  ('AI Tools', 'ai-tools', ' '),  ('Business', 'business', ' '),  ('Analytics', 'analytics', ' '),  ('Templates', 'templates', ' ');
-- ─────────────────────────────────────────────-- PRODUCTS-- ─────────────────────────────────────────────create table public.products (  id uuid default uuid_generate_v4() primary key,  name text not null,  slug text not null unique,  description text,  long_description text,  price numeric(10,2) not null,  original_price numeric(10,2),  category_id integer references public.categories(id),  badge text,  rating numeric(3,2) default 5.0,  total_sales integer default 0,  is_active boolean default true,  is_featured boolean default false,  demo_url text,  download_url text,  thumbnail_url text,  features text[],  created_at timestamptz default now(),  updated_at timestamptz default now());
-- Sample productsinsert into public.products (name, slug, description, long_description, price, original_price, category_id, badge, rating, total_sales, is_featured, features) values(  'AutoFlow Pro',  'autoflow-pro',  'Complete n8n workflow bundle — 30+ pre-built automations for lead gen, email, social & CRM.',  'AutoFlow Pro is the most comprehensive n8n workflow bundle available. Whether you are scaling a freelance business or running an agency, these 30+ battle-tested automations will save you 20+ hours per week. Includes full setup documentation and video walkthroughs.',  49.00, 89.00, 1, 'BESTSELLER', 4.9, 234, true,  ARRAY['30+ workflows included', 'n8n + Make.com compatible', 'Lifetime updates', 'Setup video guide', 'Private Discord access']),(  'GPT Prompt Vault',  'gpt-prompt-vault',  '500+ battle-tested prompts for marketing, coding, content & business strategy.',  'Stop wasting time crafting prompts from scratch. The GPT Prompt Vault gives you 500+ hand-crafted, tested prompts across 12 categories. Every prompt is engineered for maximum output quality with ChatGPT-4, Claude, and Gemini.',  29.00, 59.00, 2, 'HOT', 4.8, 412, true,  ARRAY['500+ premium prompts', '12 categories', 'Copy-paste ready', 'Monthly additions', 'Works with all AI models']),(  'Client Magnet System',  'client-magnet-system',  'Full outreach automation — LinkedIn, cold email sequences, follow-ups. Land 5-10 clients/month.',  'The Client Magnet System is a complete done-for-you outreach machine. Plug in your offer, activate the sequences, and watch leads flow in. Used by 89 freelancers and agency owners to land consistent clients every single month.',  79.00, 149.00, 3, 'PREMIUM', 5.0, 89, true,  ARRAY['Email sequences (7-touch)', 'LinkedIn message scripts', 'CRM Notion template', 'Objection handling guide', '1-hour video walkthrough']),(  'AI Content Engine',  'ai-content-engine',  'Generate, schedule & publish 30 days of content in under 1 hour using AI.',  'The AI Content Engine is a complete system for creating a month of social media content in one sitting. Combine the prompt templates with the scheduling automation and you have a fully hands-off content machine.',  39.00, 69.00, 2, 'NEW', 4.7, 156, false,  ARRAY['30-day content calendar', 'Multi-platform (IG, LinkedIn, X)', 'AI prompt templates', 'Canva template pack', 'Scheduling automation']),(  'Ecom Automation Kit',  'ecom-automation-kit',  'Automate your store — inventory alerts, order confirmations, review requests & cart recovery.',  'Built for Shopify and WooCommerce store owners who want to run on autopilot. The Ecom Automation Kit handles all the post-purchase flows so you can focus on growth.',  59.00, 99.00, 1, null, 4.6, 178, false,  ARRAY['Shopify + WooCommerce', 'Abandoned cart recovery', 'Review request automation', 'Inventory alert system', 'SMS + Email templates']),(  'Business Intel Pack',  'business-intel-pack',  'Notion + Airtable dashboards for tracking revenue, clients, expenses & growth KPIs.',  'Stop flying blind in your business. The Business Intel Pack gives you a complete financial and operational intelligence system. Know your numbers at a glance — revenue, expenses, profit margins, client LTV, and growth trends.',  89.00, 159.00, 4, 'ELITE', 4.9, 67, false,  ARRAY['Notion OS dashboard', 'Airtable financial tracker', 'KPI scorecard template', 'P&L statement builder', 'Quarterly review system']);
-- ─────────────────────────────────────────────-- ORDERS-- ─────────────────────────────────────────────create table public.orders (  id uuid default uuid_generate_v4() primary key,  user_id uuid references public.profiles(id) on delete cascade,  status text default 'pending' check (status in ('pending','paid','delivered','refunded','cancelled')),  total numeric(10,2) not null,  payment_method text default 'card',  payment_ref text,  notes text,  created_at timestamptz default now(),  updated_at timestamptz default now());
-- ─────────────────────────────────────────────-- ORDER ITEMS-- ─────────────────────────────────────────────create table public.order_items (  id uuid default uuid_generate_v4() primary key,  order_id uuid references public.orders(id) on delete cascade,  product_id uuid references public.products(id),  product_name text,  price numeric(10,2),  quantity integer default 1);
-- ─────────────────────────────────────────────-- PURCHASES (quick access — has user bought product?)-- ─────────────────────────────────────────────create table public.purchases (  id uuid default uuid_generate_v4() primary key,  user_id uuid references public.profiles(id) on delete cascade,  product_id uuid references public.products(id) on delete cascade,  order_id uuid references public.orders(id),  purchased_at timestamptz default now(),  unique(user_id, product_id));
-- ─────────────────────────────────────────────-- EXPENSES (for admin profit tracking)-- ─────────────────────────────────────────────create table public.expenses (  id uuid default uuid_generate_v4() primary key,  title text not null,  amount numeric(10,2) not null,  category text,  date date default current_date,  notes text,  created_at timestamptz default now());
-- Sample expensesinsert into public.expenses (title, amount, category, date) values  ('Supabase Pro (if upgraded)', 0, 'Hosting', current_date - 30),  ('Domain renewal', 12, 'Infrastructure', current_date - 20),  ('Canva Pro', 13, 'Tools', current_date - 15),  ('Email marketing tool', 0, 'Marketing', current_date - 10);
-- ─────────────────────────────────────────────-- ROW LEVEL SECURITY-- ─────────────────────────────────────────────
-- Profiles: users see only their ownalter table public.profiles enable row level security;create policy "Users can view own profile" on public.profiles for select using (auth.uid() = id);create policy "Users can update own profile" on public.profiles for update using (auth.uid() = id);
-- Products: everyone can read active productsalter table public.products enable row level security;create policy "Anyone can view active products" on public.products for select using (is_active = true);create policy "Admins can manage products" on public.products for all using (  exists (select 1 from public.profiles where id = auth.uid() and is_admin = true));
-- Orders: users see only their ownalter table public.orders enable row level security;create policy "Users can view own orders" on public.orders for select using (auth.uid() = user_id);create policy "Users can create orders" on public.orders for insert with check (auth.uid() = user_id);create policy "Admins can view all orders" on public.orders for select using (  exists (select 1 from public.profiles where id = auth.uid() and is_admin = true));
-- Order itemsalter table public.order_items enable row level security;create policy "Users can view own order items" on public.order_items for select using (  exists (select 1 from public.orders where id = order_id and user_id = auth.uid()));create policy "Users can insert order items" on public.order_items for insert with check (true);
-- Purchasesalter table public.purchases enable row level security;create policy "Users can view own purchases" on public.purchases for select using (auth.uid() = user_id);create policy "Users can insert purchases" on public.purchases for insert with check (auth.uid() = user_id);
-- Expenses: admin onlyalter table public.expenses enable row level security;create policy "Admins can manage expenses" on public.expenses for all using (  exists (select 1 from public.profiles where id = auth.uid() and is_admin = true));
-- ─────────────────────────────────────────────-- ANALYTICS VIEW (for dashboard)-- ─────────────────────────────────────────────create or replace view public.sales_analytics asselect  date_trunc('day', o.created_at) as day,  count(distinct o.id) as orders_count,  sum(o.total) as revenue,  count(distinct o.user_id) as unique_buyersfrom public.orders owhere o.status = 'paid'group by 1order by 1 desc;
